const request = items[0]?.json || {};
const input = request.body || request;
const payload = input.payload || {};
const description = String(payload.description || '').trim();
const correlationId = String(input.correlation_id || '').trim();
const alertId = Number(payload.alert_id || 0);
if (!correlationId || !Number.isFinite(alertId) || alertId <= 0) {
  return [];
}
const startedAt = String(input.occurred_at || new Date().toISOString());
const photoCount = Number(payload.photo_count || 0);
const contextLines = [
  `Alert-ID: ${alertId}`,
  `Beschreibung: ${description || '<leer>'}`,
  `Prioritaet: ${String(payload.priority || input.picking_context?.priority || '0')}`,
  `Fotos vorhanden: ${photoCount > 0 ? `ja (${photoCount})` : 'nein'}`,
  payload.product_id ? `Produkt-ID: ${payload.product_id}` : '',
  payload.location_id ? `Lagerort-ID: ${payload.location_id}` : '',
  'Wichtig: Diese Welle ist text-first. Es stehen keine Bildinhalte zur Verfuegung.',
].filter(Boolean).join('\n');
const systemPrompt = [
  'Du klassifizierst Quality Alerts fuer eine wissenschaftliche Shadow-Evaluation.',
  'Nutze exakt eine Kategorie: damage, shortage, wrong_item, unclear.',
  'damage = physischer Schaden, shortage = Fehlmenge, wrong_item = falsches Produkt, unclear = nicht eindeutig.',
  'Nutze nur die gegebene Beschreibung und den mitgelieferten Kontext.',
  'Erfinde keine Fakten und gib ausschliesslich JSON mit category, confidence und reason zurueck.'
].join(' ');
return [{ json: {
  correlation_id: correlationId,
  alert_id: alertId,
  occurred_at: startedAt,
  shadow_started_ms: Date.now(),
  model: 'gpt-4o-mini',
  system_prompt: systemPrompt,
  user_prompt: contextLines,
} }];

const item = items[0]?.json || {};
const content = item.choices?.[0]?.message?.content;
if (!content || typeof content !== 'string') {
  return [];
}
let parsed;
try {
  parsed = JSON.parse(content);
} catch {
  return [];
}
const validCategories = ['damage', 'shortage', 'wrong_item', 'unclear'];
const category = String(parsed.category || '').trim();
const reason = String(parsed.reason || '').trim();
const confidence = Number(parsed.confidence);
if (!validCategories.includes(category)) {
  return [];
}
if (!Number.isFinite(confidence) || confidence < 0 || confidence > 1) {
  return [];
}
if (!reason) {
  return [];
}
const callbackStartedMs = Date.now();
const shadowStartedMs = Number(item.shadow_started_ms || callbackStartedMs);
const occurredAtMs = Date.parse(String(item.occurred_at || ''));
const aiShadowMs = Math.max(0, callbackStartedMs - shadowStartedMs);
const totalDurationMs = Number.isFinite(occurredAtMs) ? Math.max(0, callbackStartedMs - occurredAtMs) : aiShadowMs;
const ingestMs = Number.isFinite(occurredAtMs) ? Math.max(0, shadowStartedMs - occurredAtMs) : null;
const latencyTracking = {
  started_at: String(item.occurred_at || new Date(shadowStartedMs).toISOString()),
  total_duration_ms: totalDurationMs,
  stages: {
    callback_ms: 0,
  },
  extra_stages: {
    ai_shadow_ms: aiShadowMs,
  },
};
if (ingestMs !== null) {
  latencyTracking.stages.ingest_ms = ingestMs;
}
return [{ json: {
  schema_version: 'v1',
  execution_id: [$workflow.id, $execution.id].filter(Boolean).join('-') || null,
  correlation_id: item.correlation_id,
  alert_id: item.alert_id,
  category,
  confidence: Math.round(confidence * 100) / 100,
  reason,
  model: item.model || 'gpt-4o-mini',
  latency_tracking: latencyTracking,
} }];
